// ----- Reactors -----

func b_combatLoop(t *starlark.Thread, fn *starlark.Builtin, args starlark.Tuple, kwargs []starlark.Tuple) (starlark.Value, error) {
	var target string
	var kills int = 5
	var hpThreshold float64 = 0.4
	if err := starlark.UnpackArgs(fn.Name(), args, kwargs, "target", &target, "kills?", &kills, "auto_eat_below?", &hpThreshold); err != nil {
		return nil, err
	}
	h := hostFromThread(t)
	opts := runtime.DefaultCombatLoopOptions()
	opts.MaxKills = kills
	opts.AutoEatHPFraction = hpThreshold
	// Resolve target by name.
	opts.TargetTypeIDs = nil
	for id, def := range h.Facts().NpcDefs {
		if def != nil && def.Attackable && (def.Name == target || containsFold(def.Name, target)) {
			opts.TargetTypeIDs = append(opts.TargetTypeIDs, id)
		}
	}
	if len(opts.TargetTypeIDs) == 0 {
		return nil, fmt.Errorf("combat_loop: no attackable NPC matches %q", target)
	}
	if err := h.CombatLoop(ctxFromThread(t), opts); err != nil {
		return nil, fmt.Errorf("combat_loop: %w", err)
	}
	return starlark.None, nil
}

// ----- Utility -----

func b_sleep(t *starlark.Thread, fn *starlark.Builtin, args starlark.Tuple, kwargs []starlark.Tuple) (starlark.Value, error) {
	var secs float64
	if err := starlark.UnpackArgs(fn.Name(), args, kwargs, "seconds", &secs); err != nil {
		return nil, err
	}
	d := time.Duration(secs * float64(time.Second))
	select {
	case <-ctxFromThread(t).Done():
		return nil, ctxFromThread(t).Err()
	case <-time.After(d):
	}
	return starlark.None, nil
}

